function centerStageInit(){$("#center-stage li.show").show();currentCenterStage=0;totalCenterStage=$("#center-stage li").size();setupRotator();$("#rotator-indicators li:eq(0) a").css("height","15px");timer=setTimeout("centerStageOut()",contentDuration)}function centerStageIn(){$("#center-stage li.show h1").animate({left:0},slideInSpeed,"easeInOutQuad");var e=0;$("#center-stage li.show img").each(function(){$(this).delay(timeBetweenTransitions*e+timeBetweenTransitions).animate({right:imageXCoord[e]},slideInSpeed,"easeInOutQuad");e++});$("#center-stage li.show .center-stage-border").delay(timeBetweenTransitions*(e+1)+timeBetweenTransitions).animate({top:135},slideInSpeed,"easeInOutQuad");$("#center-stage li.show p").delay(timeBetweenTransitions*(e+1)+timeBetweenTransitions).fadeIn(slideInSpeed/2,function(){isChanging=false});$("#center-stage li.show h2").delay(timeBetweenTransitions*(e+1)+timeBetweenTransitions).fadeIn(slideInSpeed/2,function(){isChanging=false});if(!galleryStopped)timer=setTimeout("centerStageOut()",contentDuration)}function centerStageOut(){isChanging=true;if($.browser.msie){$("#center-stage li.show h1").fadeOut(fadeOutSpeed,resetCenterStage);$("#center-stage li.show img").fadeOut(fadeOutSpeed);$("#center-stage li.show p").fadeOut(fadeOutSpeed);$("#center-stage li.show h2").fadeOut(fadeOutSpeed);$("#center-stage li.show .center-stage-border").fadeOut(fadeOutSpeed)}else{$("#center-stage li.show").fadeOut(fadeOutSpeed,resetCenterStage)}$("#rotator-indicators li:eq("+currentCenterStage+") a").animate({height:0},500,"easeInOutQuad")}function resetCenterStage(){$("#center-stage li.show").hide();if(currentCenterStage<totalCenterStage-1){$("#center-stage li.show").removeClass("show");currentCenterStage++;$("#center-stage li:eq("+currentCenterStage+")").addClass("show")}else{$("#center-stage li.show").removeClass("show");$("#center-stage li:first").addClass("show");currentCenterStage=0}$("#rotator-indicators li:eq("+currentCenterStage+") a").delay(250).animate({height:15},500,"easeInOutQuad");findScreenWidth();var e=(screenWidth-904)/2*-1-550;imageXCoord=new Array;$("#center-stage li.show img").each(function(){imageXCoord.push($(this).css("right"))});$("#center-stage li.show h1").css("left",e+"px").fadeIn(1);$("#center-stage li.show img").css("right",e+"px").fadeIn(1);$("#center-stage li.show .center-stage-border").css("top","365px").fadeIn(1);$("#center-stage li.show").fadeIn(1);$("#center-stage li.show p").fadeOut(0);$("#center-stage li.show h2").fadeOut(0);centerStageIn()}function setupRotator(){for(var e=0;e<totalCenterStage;e++){var t=$("#center-stage li:eq("+e+")").attr("class");$("#rotator-indicators ul").append("<li><a class='"+t+"'></a></li>");$("#center-stage-left").css("left",128-totalCenterStage*21/2-25+"px");$("#center-stage-right").css("right",128-totalCenterStage*21/2-22+"px")}$("#rotator-indicators ul").css("width",totalCenterStage*21);$("#rotator-indicators li").hover(function(){$(this).fadeTo(1,.6)},function(){$(this).fadeTo(1,1)});$("#rotator-indicators li").click(function(){if(!isChanging){centerStageOut();clearTimeout(timer);var e=$(this).index();currentCenterStage=e-1;galleryStopped=true}});$("#center-stage-left").click(function(){if(!isChanging){centerStageOut();clearTimeout(timer);if(currentCenterStage==0)currentCenterStage=totalCenterStage-2;else currentCenterStage=currentCenterStage-2;galleryStopped=true}});$("#center-stage-right").click(function(){if(!isChanging){centerStageOut();clearTimeout(timer);if(currentCenterStage==totalCenterStage)currentCenterStage=-1;galleryStopped=true}})}function findScreenWidth(){screenWidth=$(window).width()}var contentDuration=1e4;var slideInSpeed=750;var fadeOutSpeed=750;var timeBetweenTransitions=250;var timer;var screenWidth;var imageXCoord;var currentCenterStage;var totalCenterStage;var isChanging=false;var galleryStopped=false;$(document).ready(centerStageInit)